  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\n// ==========================================\n// 1. ENTIDADE MASTER DE USUÁRIO\n// ==========================================\nmodel User {\n  id       String  @id @default(uuid())\n  email    String  @unique\n  password String\n  isAdmin  Boolean @default(false) // Permite login no App de Moderação\n\n  // --- TRAVA DE SEGURANÇA DA MODERAÇÃO ---\n  isFlagged Boolean @default(false) // Protege contra deleção automática\n\n  createdAt    DateTime @default(now())\n  lastActiveAt DateTime @default(now())\n\n  // Relacionamentos básicos\n  profile      Profile?\n  chatsAsUser1 MatchHistory[] @relation(\"User1Chats\")\n  chatsAsUser2 MatchHistory[] @relation(\"User2Chats\")\n  messages     ChatMessage[]\n\n  // Relacionamentos focados em Moderação\n  reportsFiled    Report[]        @relation(\"ReporterRelation\") // Denúncias que este usuário FEZ\n  reportsReceived Report[]        @relation(\"OffenderRelation\") // Denúncias que este usuário RECEBEU\n  actionsTaken    ModerationLog[] @relation(\"AdminActions\") // Ações se ele for um Admin\n\n  @@index([id])\n  @@index([isFlagged])\n}\n\n// ==========================================\n// 2. PERFIL DE IDENTIFICAÇÃO (ID, GÊNERO, IDADE)\n// ==========================================\nmodel Profile {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  nickname String\n  realName String?\n  photoUrl String? // Foto vinculada diretamente ao ID\n  myGender String\n  myAge    Int\n\n  searchingForGender String @default(\"all\")\n  minAge             Int    @default(18)\n  maxAge             Int    @default(99)\n\n  updatedAt DateTime @updatedAt\n\n  @@index([myGender, myAge])\n}\n\n// ==========================================\n// 3. HISTÓRICO DE CONVERSAS (CHAVE MESTRA)\n// ==========================================\nmodel MatchHistory {\n  id            String   @id @default(uuid())\n  roomId        String   @unique // Mesmo ID gerado no Redis\n  user1Id       String\n  user2Id       String\n  createdAt     DateTime @default(now())\n  lastMessageAt DateTime @default(now())\n\n  // --- TRAVA DE SEGURANÇA DA CONVERSA ---\n  isFrozen Boolean @default(false) // Protege este chat específico do robô de 45 dias\n\n  user1    User          @relation(\"User1Chats\", fields: [user1Id], references: [id], onDelete: Cascade)\n  user2    User          @relation(\"User2Chats\", fields: [user2Id], references: [id], onDelete: Cascade)\n  messages ChatMessage[]\n  reports  Report[] // Denúncias vinculadas a esta conversa\n\n  @@index([roomId])\n  @@index([user1Id, user2Id])\n  @@index([createdAt, lastMessageAt])\n  @@index([isFrozen])\n}\n\n// ==========================================\n// 4. HISTÓRICO DE MENSAGENS E MÍDIAS\n// ==========================================\nmodel ChatMessage {\n  id       String       @id @default(uuid())\n  roomId   String\n  match    MatchHistory @relation(fields: [roomId], references: [roomId], onDelete: Cascade)\n  senderId String\n  sender   User         @relation(fields: [senderId], references: [id], onDelete: Cascade)\n\n  content   String   @db.Text\n  mediaType String   @default(\"text\")\n  createdAt DateTime @default(now())\n\n  @@index([roomId])\n  @@index([senderId])\n}\n\n// ==========================================\n// 5. NOVA TABELA: PAINEL DE DENÚNCIAS (FLUXO DO APP ADMIN)\n// ==========================================\nmodel Report {\n  id     String       @id @default(uuid())\n  roomId String // O ID da sala onde ocorreu a infração\n  match  MatchHistory @relation(fields: [roomId], references: [roomId], onDelete: Cascade)\n\n  reporterId String // Quem denunciou\n  reporter   User   @relation(\"ReporterRelation\", fields: [reporterId], references: [id], onDelete: Cascade)\n\n  offenderId String // O acusado\n  offender   User   @relation(\"OffenderRelation\", fields: [offenderId], references: [id], onDelete: Cascade)\n\n  reason    String // Motivo: 'assédio', 'nudez', 'menor de idade', etc.\n  status    String   @default(\"PENDING\") // 'PENDING' | 'INVESTIGATING' | 'RESOLVED'\n  createdAt DateTime @default(now())\n\n  @@index([status])\n  @@index([offenderId])\n}\n\n// ==========================================\n// 6. NOVA TABELA: AUDITORIA INTERNA DOS MODERADORES\n// ==========================================\nmodel ModerationLog {\n  id      String @id @default(uuid())\n  adminId String // O ID do moderador que realizou a ação\n  admin   User   @relation(\"AdminActions\", fields: [adminId], references: [id], onDelete: Cascade)\n\n  action    String // 'SPY_ROOM' | 'FLAG_USER' | 'FREEZE_CHAT' | 'BAN_USER'\n  targetId  String // ID do usuário ou da sala que sofreu a ação\n  details   String? // Justificativa ou notas do moderador\n  createdAt DateTime @default(now())\n\n  @@index([adminId])\n}\n",
  "inlineSchemaHash": "d7e378f9ed3da9dc12d07bb6f726ace3a70033b8e5a010f60b62d4e7291767f2",
